+
+                // Update selected columns
+                const selectColsEl = document.getElementById('df-select-cols');
+                if (query.select && query.select.length > 0) {
+                    // Store pending selection for when options load
+                    selectColsEl.setAttribute('data-pending-columns', JSON.stringify(query.select));
+                    // Try to apply now if options exist
+                    const colNames = currentFile?.columnNames || [];
+                    if (selectColsEl.options.length > 0) {
+                        for (let opt of selectColsEl.options) {
+                            const optColName = opt.text;
+                            opt.selected = query.select.some(c => c.toLowerCase() === optColName.toLowerCase());
+                        }
+                        selectColsEl.removeAttribute('data-pending-columns');
+                    }
+                } else {
+                    // Select all columns (no specific selection = *)
+                    selectColsEl.removeAttribute('data-pending-columns');
+                    for (let opt of selectColsEl.options) {
+                        opt.selected = true;
+                    }
+                }
             }

